"use strict";

const mongoose = require('mongoose');
const productSchema = new mongoose.Schema({
  // Basic Information
  name: {
    type: String,
    required: true
  },
  description: String,
  brand: {
    type: String,
    required: true
  },
  category: {
    type: String,
    enum: ['Seeds', 'Herbicides', 'Insecticides', 'Fertilizers', 'Fungicides', 'Tools', 'Equipment', 'Organic Products'],
    default: 'Seeds'
  },
  // Pricing
  price: {
    type: Number,
    required: true
  },
  // Main price (for display, usually smallest package)
  basePrice: {
    type: Number,
    required: true
  },
  // Base price per base unit
  baseUnit: {
    type: String,
    required: true,
    default: 'kg'
  },
  // Base unit for pricing
  originalPrice: {
    type: Number
  },
  // For showing discounts
  discount: {
    type: Number,
    default: 0
  },
  // Percentage discount
  packageSizes: [{
    // Available package sizes
    size: {
      type: Number,
      required: true
    },
    // Package size (e.g., 1, 5, 10)
    unit: {
      type: String,
      required: true
    },
    // Unit for this package (kg, liter, etc.)
    priceMultiplier: {
      type: Number,
      default: 1
    },
    // Multiplier for bulk pricing
    price: {
      type: Number,
      required: true
    },
    // Calculated price for this package
    stock: {
      type: Number,
      default: 0
    } // Stock for this specific package size
  }],
  priceBreaks: [{
    // Quantity-based pricing (legacy, for compatibility)
    minQuantity: {
      type: Number,
      required: true
    },
    pricePerUnit: {
      type: Number,
      required: true
    }
  }],
  // Inventory
  available: {
    type: Boolean,
    default: true
  },
  prebooked: {
    type: Number,
    default: 0
  },
  prebookingEnabled: {
    type: Boolean,
    default: true
  },
  unit: {
    type: String,
    default: 'bags'
  },
  stock: {
    type: Number,
    default: 100
  },
  weight: {
