// Debug endpoint to check user existence
router.get('/debug/user/:userId', async (req, res) => {
  try {
    const {
      userId
    } = req.params;
    console.log('Debug: Checking user ID:', userId);
    const user = await User.findById(userId);
    if (!user) {
