"use strict";

const express = require('express');
const Order = require('../models/Order.js');
const Product = require('../models/Product.js');
const mongoose = require('mongoose');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const WhatsAppNotificationService = require('../services/WhatsAppNotificationService');
const router = express.Router();

// Initialize WhatsApp service
const whatsappService = new WhatsAppNotificationService();

// Configure multer for file upload
const uploadsDir = path.join(__dirname, '../uploads');
if (!fs.existsSync(uploadsDir)) {
  fs.mkdirSync(uploadsDir, {
    recursive: true
  });
}
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, uploadsDir);
  },
  filename: function (req, file, cb) {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    cb(null, 'product-' + uniqueSuffix + path.extname(file.originalname));
  }
});
const fileFilter = (req, file, cb) => {
  if (file.mimetype.startsWith('image/')) {
    cb(null, true);
  } else {
    cb(new Error('Only image files are allowed!'), false);
  }
};
const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: 5 * 1024 * 1024 // 5MB limit
  }
});

// Category Schema for storing custom categories
const categorySchema = new mongoose.Schema({
  name: {
    type: String,
    required: true,
    unique: true
  },
  description: String,
  icon: String,
  isActive: {
    type: Boolean,
    default: true
  },
  createdBy: String,
  createdAt: {
    type: Date,
    default: Date.now
  }
});
const Category = mongoose.model('Category', categorySchema);

// Category Routes
router.get('/categories', async (req, res) => {
  try {
    const categories = await Category.find({
      isActive: true
    }).sort({
      name: 1
    });
    res.json({
      categories
    });
  } catch (error) {
    res.status(500).json({
      error: 'Failed to fetch categories'
    });
  }
});
router.post('/categories', async (req, res) => {
  try {
    const {
      name,
      description,
      icon
    } = req.body;
    if (!name || !description) {
      return res.status(400).json({
        error: 'Name and description are required'
      });
    }
    const category = new Category({
      name: name.toLowerCase(),
      description,
      icon: icon || '📦',
      createdBy: 'admin'
    });
    await category.save();
    res.status(201).json({
      message: 'Category created successfully',
      category
    });
  } catch (error) {
    if (error.code === 11000) {
      return res.status(400).json({
        error: 'Category already exists'
      });
    }
    res.status(500).json({
      error: 'Failed to create category'
    });
  }
});

// Stock monitoring route
router.get('/stock-alerts', async (req, res) => {
  try {
    const lowStockProducts = await Product.find({
      stock: {
        $lt: 10
      }
    });
    const outOfStockProducts = await Product.find({
      stock: {
        $lte: 0
      }
    });
    res.json({
      lowStockProducts,
      outOfStockProducts,
      totalLowStock: lowStockProducts.length,
      totalOutOfStock: outOfStockProducts.length
    });
  } catch (error) {
    res.status(500).json({
      error: 'Failed to fetch stock alerts'
    });
  }
});

// Send WhatsApp notification for out of stock
router.post('/notify-out-of-stock/:productId', async (req, res) => {
  try {
    const product = await Product.findById(req.params.productId);
    if (!product) {
      return res.status(404).json({
        error: 'Product not found'
      });
    }
    const result = await whatsappService.sendOutOfStockNotification(product);
    res.json(result);
  } catch (error) {
    res.status(500).json({
      error: 'Failed to send notification'
    });
  }
});

// Send bulk low stock alert
router.post('/notify-low-stock', async (req, res) => {
  try {
    const lowStockProducts = await Product.find({
      stock: {
        $lt: 10,
        $gt: 0
      }
    });
    if (lowStockProducts.length === 0) {
      return res.json({
        message: 'No low stock products found'
      });
    }
    const result = await whatsappService.sendLowStockAlert(lowStockProducts);
    res.json(result);
  } catch (error) {
    res.status(500).json({
      error: 'Failed to send low stock alert'
    });
  }
});

// Get all orders for admin
router.get('/orders', async (req, res) => {
  try {
    const orders = await Order.find().populate('user', 'username email fullName').populate('items.product', 'name price category brand').populate('products', 'name price category').sort({
      createdAt: -1
    });
    console.log('Orders fetched:', orders.length);
    if (orders.length > 0) {
      console.log('Sample order structure:', {
        id: orders[0]._id,
        items: orders[0].items,
        products: orders[0].products,
        hasItems: !!orders[0].items,
        itemsLength: orders[0].items?.length || 0
      });
    }

    // Transform orders to include customer name and formatted date
    const transformedOrders = orders.map(order => ({
      ...order.toObject(),
      customerName: order.user?.username || order.deliveryAddress?.fullName || 'Unknown Customer',
      orderDate: order.createdAt,
      formattedDate: order.createdAt.toLocaleDateString('en-IN'),
      formattedTime: order.createdAt.toLocaleTimeString('en-IN')
    }));
    res.json(transformedOrders);
  } catch (error) {
    console.error('Error fetching orders:', error);
    res.status(500).json({
      error: 'Failed to fetch orders'
    });
  }
});

